    const initialCheckboxes = page.locator('[role="checkbox"]');
    const initialCount = await initialCheckboxes.count();

    if (initialCount > 0) {
      // Delete all existing todos
      page.on('dialog', async (dialog) => {
        await dialog.accept();
      });

      for (let i = 0; i < initialCount; i++) {
        const deleteButtons = page.getByRole('button', { name: /delete/i });
        const firstDelete = deleteButtons.first();
        await firstDelete.click();
        await page.waitForTimeout(500);
      }
    }

    // Verify empty state is shown
    await expect(page.getByText(/no todos yet/i)).toBeVisible();
    await expect(page.getByText(/create your first one/i)).toBeVisible();

    // Create a single todo
    await page.getByLabel(/title/i).fill('Last Todo Standing');
    await page.getByRole('button', { name: /add todo/i }).click();
    await expect(page.getByLabel(/title/i)).toHaveValue('', { timeout: 10000 });

    // Verify empty state is gone
    await expect(page.getByText(/no todos yet/i)).not.toBeVisible();
    await expect(page.getByText('Last Todo Standing')).toBeVisible();

    // Delete the only todo
    page.on('dialog', async (dialog) => {
      await dialog.accept();
    });

    const deleteButton = page.getByRole('button', { name: /delete/i });
    await deleteButton.click();
    await page.waitForTimeout(1000);

    // Verify empty state appears again
    await expect(page.getByText(/no todos yet/i)).toBeVisible();
    await expect(page.getByText(/create your first one/i)).toBeVisible();
    await expect(page.getByText('Last Todo Standing')).not.toBeVisible();
  });
});

